  1→/**
  2→ * Basement Lab - Workout Tracker
  3→ * State management and UI logic
  4→ */
  5→
  6→const STATE_KEY = 'basement_lab_state';
  7→const LOG_KEY = 'basement_lab_log';
  8→const THEME_KEY = 'basement_lab_theme';
  9→const MODE_KEY = 'basement_lab_mode';
 10→
 11→let programData = null;
 12→let currentState = null;
 13→
 14→// Initialize app
 15→async function init() {
 16→  loadState();
 17→  initTheme();
 18→  await loadProgram();
 19→  render();
 20→  bindEvents();
 21→}
 22→
 23→// Initialize theme and mode from localStorage or system preference
 24→function initTheme() {
 25→  const savedTheme = localStorage.getItem(THEME_KEY) || 'cyberpunk';
 26→  const savedMode = localStorage.getItem(MODE_KEY) ||
 27→    (window.matchMedia('(prefers-color-scheme: light)').matches ? 'light' : 'dark');
 28→
 29→  setTheme(savedTheme);
 30→  setMode(savedMode);
 31→  updateSettingsUI();
 32→}
 33→
 34→// Set theme (cyberpunk, material, ocean, ember)
 35→function setTheme(theme) {
 36→  document.documentElement.setAttribute('data-theme', theme);
 37→  localStorage.setItem(THEME_KEY, theme);
 38→  updateSettingsUI();
 39→}
 40→
 41→// Set mode (dark, light)
 42→function setMode(mode) {
 43→  document.documentElement.setAttribute('data-mode', mode);
 44→  localStorage.setItem(MODE_KEY, mode);
 45→
 46→  // Update meta theme-color based on mode
 47→  const metaThemeColor = document.querySelector('meta[name="theme-color"]');
 48→  if (metaThemeColor) {
 49→    metaThemeColor.setAttribute('content', mode === 'light' ? '#f5f5f5' : '#0a0a0a');
 50→  }
 51→
 52→  updateSettingsUI();
 53→}
 54→
 55→// Update settings modal UI to reflect current theme/mode
 56→function updateSettingsUI() {
 57→  const currentTheme = document.documentElement.getAttribute('data-theme') || 'cyberpunk';
 58→  const currentMode = document.documentElement.getAttribute('data-mode') || 'dark';
 59→
 60→  // Update theme options
 61→  document.querySelectorAll('.theme-option').forEach(option => {
 62→    if (option.dataset.theme === currentTheme) {
 63→      option.classList.add('active');
 64→    } else {
 65→      option.classList.remove('active');
 66→    }
 67→  });
 68→
 69→  // Update mode buttons
 70→  document.querySelectorAll('.mode-btn').forEach(btn => {
 71→    if (btn.dataset.mode === currentMode) {
 72→      btn.classList.add('active');
 73→    } else {
 74→      btn.classList.remove('active');
 75→    }
 76→  });
 77→}
 78→
 79→// Open settings modal
 80→function openSettings() {
 81→  updateSettingsUI();
 82→  document.getElementById('settings-modal').classList.remove('hidden');
 83→}
 84→
 85→// Close settings modal
 86→function closeSettings() {
 87→  document.getElementById('settings-modal').classList.add('hidden');
 88→}
 89→
 90→// Load state from localStorage
 91→function loadState() {
 92→  const saved = localStorage.getItem(STATE_KEY);
 93→  if (saved) {
 94→    currentState = JSON.parse(saved);
 95→  } else {
 96→    currentState = {
 97→      globalDay: 1,
 98→      currentPhase: 'p1'
 99→    };
100→    saveState();
101→  }
102→}
103→
104→// Save state to localStorage
105→function saveState() {
106→  localStorage.setItem(STATE_KEY, JSON.stringify(currentState));
107→}
108→
109→// Load exercise log from localStorage
110→function loadLog() {
111→  const saved = localStorage.getItem(LOG_KEY);
112→  return saved ? JSON.parse(saved) : {};
113→}
114→
115→// Save exercise log to localStorage
116→function saveLog(log) {
117→  localStorage.setItem(LOG_KEY, JSON.stringify(log));
118→}
119→
120→// Load program data from JSON
121→async function loadProgram() {
122→  try {
123→    const response = await fetch('data/program.json');
124→    programData = await response.json();
125→  } catch (error) {
126→    console.error('Failed to load program:', error);
127→    document.getElementById('workout-name').textContent = 'Error loading program';
128→  }
129→}
130→
131→// Get current phase data
132→function getCurrentPhase() {
133→  if (!programData) return null;
134→  return programData.phases.find(p => p.id === currentState.currentPhase);
135→}
136→
137→// Get workout type for current day
138→function getWorkoutType() {
139→  const phase = getCurrentPhase();
140→  if (!phase || !phase.schedule_pattern) return null;
141→
142→  // Day 1 = index 0, so subtract 1
143→  const dayIndex = (currentState.globalDay - 1) % phase.schedule_pattern.length;
144→  return phase.schedule_pattern[dayIndex];
145→}
146→
147→// Get workout data for current day
148→function getTodaysWorkout() {
149→  const phase = getCurrentPhase();
150→  const workoutType = getWorkoutType();
151→
152→  if (!phase || !workoutType || workoutType === 'Rest') {
153→    return null;
154→  }
155→
156→  return phase.workouts[workoutType];
157→}
158→
159→// Render the UI
160→function render() {
161→  // Update day counter
162→  document.getElementById('current-day').textContent = currentState.globalDay;
163→
164→  const workout = getTodaysWorkout();
165→  const workoutCard = document.getElementById('workout-card');
166→  const restDay = document.getElementById('rest-day');
167→
168→  if (!workout) {
169→    // Rest day
170→    workoutCard.classList.add('hidden');
171→    restDay.classList.remove('hidden');
172→    document.getElementById('session-progress').style.display = 'none';
173→    return;
174→  }
175→
176→  document.getElementById('session-progress').style.display = '';
177→
178→  // Workout day
179→  workoutCard.classList.remove('hidden');
180→  restDay.classList.add('hidden');
181→
182→  document.getElementById('workout-name').textContent = workout.name;
183→  document.getElementById('workout-focus').textContent = workout.focus;
184→
185→  const exercisesList = document.getElementById('exercises-list');
186→  const log = loadLog();
187→
188→  exercisesList.innerHTML = workout.exercises.map((ex, index) => {
189→    const exerciseKey = `${currentState.globalDay}_${index}`;
190→    const logEntry = log[exerciseKey] || {};
191→    const currentWeight = logEntry.weight || '';
192→    const currentDifficulty = logEntry.difficulty || '';
193→    const currentNotes = logEntry.notes || '';
194→
195→    // Calculate suggested weight for weight-based exercises
196→    const suggestedWeight = ex.uses_weight
197→      ? getSuggestedWeight(ex.name, ex.starting_weight, ex.weight_increment || 5)
198→      : null;
199→    const increment = ex.weight_increment || 5;
200→
201→    // Build weight input section
202→    let weightSection = '';
203→    if (ex.uses_weight) {
204→      weightSection = `
205→        <div class="weight-input">
206→          <label>Weight:</label>
207→          <div class="weight-controls">
208→            <button class="weight-btn" data-action="decrement" data-key="${exerciseKey}" data-increment="${increment}">-</button>
209→            <input type="number"
210→                   class="weight-field"
211→                   data-exercise="${ex.name}"
212→                   data-key="${exerciseKey}"
213→                   value="${currentWeight}"
214→                   placeholder="${suggestedWeight}">
215→            <button class="weight-btn" data-action="increment" data-key="${exerciseKey}" data-increment="${increment}">+</button>
216→          </div>
217→          <span class="unit">lbs</span>
218→          <span class="suggested-hint">suggested: ${suggestedWeight}</span>
219→        </div>
220→      `;
221→    } else if (ex.uses_weight !== false) {
222→      // Legacy exercises without uses_weight defined - show basic input
223→      const lastWeight = getLastWeight(ex.name);
224→      weightSection = `
225→        <div class="weight-input">
226→          <label>Weight:</label>
227→          <input type="number"
228→                 class="weight-field"
229→                 data-exercise="${ex.name}"
230→                 data-key="${exerciseKey}"
231→                 value="${currentWeight}"
232→                 placeholder="${lastWeight || '—'}">
233→          <span class="unit">lbs</span>
234→        </div>
235→      `;
236→    }
237→
238→    // Build collapsible feedback section (difficulty + notes)
239→    const isCompleted = logEntry.completed || false;
240→    const hasCustomFeedback = currentDifficulty && currentDifficulty !== 'good' || currentNotes;
241→    const maxSets = ex.sets;
242→    const maxReps = parseReps(ex.reps);
243→    const failedSet = logEntry.failedSet || 1;
244→    const failedRep = logEntry.failedRep || 1;
245→
246→    const feedbackSection = `
247→      <div class="feedback-section${isCompleted && hasCustomFeedback ? ' expanded' : ''}">
248→        <button class="done-btn${isCompleted ? ' is-done' : ''}" data-key="${exerciseKey}" data-exercise="${ex.name}" data-index="${index}">
249→          ${isCompleted ? '\u2713 DONE' : 'DONE'}
250→        </button>
251→        <div class="feedback-content">
252→          <div class="difficulty-input">
253→            <label>How was it?</label>
254→            <div class="difficulty-buttons">
255→              <button class="difficulty-btn${currentDifficulty === 'failed' ? ' selected' : ''}" data-difficulty="failed" data-key="${exerciseKey}" data-exercise="${ex.name}" data-sets="${maxSets}" data-reps="${maxReps}">FAILED</button>
256→              <button class="difficulty-btn${currentDifficulty === 'easy' ? ' selected' : ''}" data-difficulty="easy" data-key="${exerciseKey}" data-exercise="${ex.name}">EASY</button>
257→              <button class="difficulty-btn${currentDifficulty === 'good' || !currentDifficulty ? ' selected' : ''}" data-difficulty="good" data-key="${exerciseKey}" data-exercise="${ex.name}">GOOD</button>
258→              <button class="difficulty-btn${currentDifficulty === 'hard' ? ' selected' : ''}" data-difficulty="hard" data-key="${exerciseKey}" data-exercise="${ex.name}">HARD</button>
259→            </div>
260→          </div>
261→          <div class="failed-details${currentDifficulty === 'failed' ? ' visible' : ''}" data-key="${exerciseKey}">
262→            <div class="slider-group">
263→              <label>Failed on set: <span class="slider-value">${failedSet}</span> / ${maxSets}</label>
264→              <input type="range" class="failed-set-slider" data-key="${exerciseKey}" data-exercise="${ex.name}" min="1" max="${maxSets}" value="${failedSet}">
265→            </div>
266→            <div class="slider-group">
267→              <label>Failed on rep: <span class="slider-value">${failedRep}</span> / ${maxReps}</label>
268→              <input type="range" class="failed-rep-slider" data-key="${exerciseKey}" data-exercise="${ex.name}" min="1" max="${maxReps}" value="${failedRep}">
269→            </div>
270→          </div>
271→          <div class="notes-input">
272→            <textarea class="notes-field" data-key="${exerciseKey}" data-exercise="${ex.name}" placeholder="Notes (optional)">${currentNotes}</textarea>
273→          </div>
274→        </div>
275→      </div>
276→    `;
277→
278→    // Build timer section
279→    let timerSection = '';
280→    const repSeconds = ExerciseTimer.parseSeconds(ex.reps);
281→    const restSeconds = ExerciseTimer.parseSeconds(ex.rest);
282→    if (repSeconds || restSeconds) {
283→      timerSection = '<div class="timer-section">';
284→      if (repSeconds) {
285→        timerSection += ExerciseTimer.renderTimerHTML(
286→          `timer_ex_${currentState.globalDay}_${index}`, repSeconds, 'EXERCISE'
287→        );
288→      }
289→      if (restSeconds) {
290→        timerSection += ExerciseTimer.renderTimerHTML(
291→          `timer_rest_${currentState.globalDay}_${index}`, restSeconds, 'REST'
292→        );
293→      }
294→      timerSection += '</div>';
295→    }
296→
297→    return `
298→      <div class="exercise${isCompleted ? ' completed' : ''}" data-index="${index}">
299→        <div class="exercise-header">
300→          <span class="exercise-name">${ex.name}</span>
301→          ${ex.video_id ? `<button class="video-btn" data-video="${ex.video_id}" data-start="${ex.video_start || 0}">VIDEO</button>` : '<button class="video-btn" disabled>NO VIDEO</button>'}
302→        </div>
303→        <div class="exercise-details">
304→          <span><strong>${ex.sets}</strong> sets</span>
305→          <span><strong>${ex.reps}</strong> reps</span>
306→          <span><strong>${ex.rest}</strong> rest</span>
307→        </div>
308→        ${ex.note ? `<div class="exercise-note">${ex.note}</div>` : ''}
309→        ${timerSection}
310→        ${weightSection}
311→        ${feedbackSection}
312→      </div>
313→    `;
314→  }).join('');
315→
316→  updateProgressBar();
317→  ExerciseTimer.initAll();
318→}
