320→// Update session progress bar
321→function updateProgressBar() {
322→  const workout = getTodaysWorkout();
323→  const bar = document.getElementById('session-progress-bar');
324→  if (!workout || !bar) {
325→    if (bar) bar.style.width = '0%';
326→    return;
327→  }
328→
329→  const log = loadLog();
330→  const total = workout.exercises.length;
331→  let completed = 0;
332→
333→  workout.exercises.forEach((ex, index) => {
334→    const key = `${currentState.globalDay}_${index}`;
335→    if (log[key] && log[key].completed) {
336→      completed++;
337→    }
338→  });
339→
340→  const percent = total > 0 ? (completed / total) * 100 : 0;
341→  bar.style.width = `${percent}%`;
342→}
