350→// Get the last recorded weight for an exercise
351→function getLastWeight(exerciseName) {
352→  const log = loadLog();
353→  let lastWeight = null;
354→  let lastDay = 0;
355→
356→  for (const key in log) {
357→    if (log[key].exercise === exerciseName && log[key].day > lastDay) {
358→      lastWeight = log[key].weight;
359→      lastDay = log[key].day;
360→    }
361→  }
362→
363→  return lastWeight;
364→}
365→
366→// Get suggested weight with weekly progression logic
367→function getSuggestedWeight(exerciseName, startingWeight, increment = 5) {
368→  const log = loadLog();
369→  const currentWeek = Math.floor((currentState.globalDay - 1) / 7) + 1;
370→
371→  // Find last logged weight for this exercise
372→  let lastEntry = null;
373→  for (const key in log) {
374→    if (log[key].exercise === exerciseName) {
375→      if (!lastEntry || log[key].timestamp > lastEntry.timestamp) {
376→        lastEntry = log[key];
377→      }
378→    }
379→  }
380→
381→  if (!lastEntry) {
382→    return startingWeight; // First time - use starting weight
383→  }
384→
385→  const lastWeek = Math.floor((lastEntry.day - 1) / 7) + 1;
386→
387→  if (currentWeek > lastWeek) {
388→    // New week - suggest progression
389→    return Math.min(lastEntry.weight + increment, 80); // Cap at 80lbs
390→  }
391→
392→  return lastEntry.weight; // Same week - same weight
393→}
