411→  if (!input) return;
412→
413→  let currentValue = parseFloat(input.value) || parseFloat(input.placeholder) || 10;
414→  const newValue = Math.max(currentValue - increment, 5); // Min 5lbs
415→  input.value = newValue;
416→
417→  // Trigger save
418→  saveWeightInput(input);
419→}
