    const body = page.locator('body');
    const fontFamily = await body.evaluate(el =>
      getComputedStyle(el).fontFamily
    );

    // Should contain Courier or monospace
    expect(fontFamily).toMatch(/courier|monospace/i);
  });

  // =============================================
  // Timer Tests
